"use client"

import { useState, useEffect } from "react"
import { useDataStore } from "@/store/data-store"
import { useAuthStore } from "@/store/auth-store"
import { EntityStatusBadge } from "@/components/shared/status-badge"
import type { EntityStatus } from "@/lib/types"
import { ConfirmDialog } from "@/components/shared/confirm-dialog"
import { Card, CardContent } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Badge } from "@/components/ui/badge"
import { Avatar, AvatarFallback } from "@/components/ui/avatar"
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
  DialogDescription,
} from "@/components/ui/dialog"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu"
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table"
import {
  MoreHorizontal,
  Pencil,
  Trash2,
  Search,
  Plus,
  Users,
  Eye,
  EyeOff,
  Phone,
  Mail,
  MapPin,
  UserCog,
  Lock,
  Building2,
  CheckCircle2,
  Sparkles,
  User,
  Calendar,
} from "lucide-react"
import { toast } from "sonner"
import { cn } from "@/lib/utils"

interface DMAManager {
  id: string
  name: string
  email: string
  phone: string | null
  role: string
  status: EntityStatus
  dmaId?: string
  dmaName?: string
  utilityId?: string
  utilityName?: string
}

export default function DMAManagersPage() {
  const { currentUser } = useAuthStore()
  const { dmas, utilities, fetchDMAs, fetchUtilities } = useDataStore()
  const [managers, setManagers] = useState<DMAManager[]>([])
  const [search, setSearch] = useState("")
  const [dialogOpen, setDialogOpen] = useState(false)
  const [viewDialogOpen, setViewDialogOpen] = useState(false)
  const [viewingManager, setViewingManager] = useState<DMAManager | null>(null)
  const [editingManager, setEditingManager] = useState<DMAManager | null>(null)
  const [deleteId, setDeleteId] = useState<string | null>(null)

  // Form state
  const [formName, setFormName] = useState("")
  const [formEmail, setFormEmail] = useState("")
  const [formPhone, setFormPhone] = useState("")
  const [formDmaId, setFormDmaId] = useState("")
  const [formStatus, setFormStatus] = useState<string>("active")
  const [formPassword, setFormPassword] = useState("")
  const [formConfirmPassword, setFormConfirmPassword] = useState("")
  const [showPassword, setShowPassword] = useState(false)

  // Fetch data on mount
  useEffect(() => {
    fetchDMAs()
    fetchUtilities()
    fetchManagers()
  }, [fetchDMAs, fetchUtilities])

  async function fetchManagers() {
    try {
      const response = await fetch("/api/dma-managers")
      if (response.ok) {
        const users = await response.json()
        setManagers(users)
      }
    } catch (error) {
      console.error("Error fetching managers:", error)
    }
  }

  // Only utility managers and admins can access this page
  const isUtilityManager = currentUser?.role === "utility_manager"
  const isAdmin = currentUser?.role === "admin"
  const canAccess = isUtilityManager || isAdmin

  // Find the utility for the current utility manager
  const myUtility = isUtilityManager 
    ? utilities.find((u) => u.managerId === currentUser?.id) 
    : null
  const myUtilityId = myUtility?.id || currentUser?.utilityId || null
  const myUtilityName = myUtility?.name || currentUser?.utilityName || "Your Utility"

  if (!canAccess) {
    return (
      <div className="flex flex-col gap-6">
        <Card className="border-slate-200/60 shadow-lg shadow-slate-200/20">
          <CardContent className="py-16 text-center">
            <div className="flex flex-col items-center gap-4">
              <div className="h-16 w-16 rounded-2xl bg-gradient-to-br from-slate-100 to-slate-200 flex items-center justify-center">
                <UserCog className="h-8 w-8 text-slate-400" />
              </div>
              <div>
                <p className="text-lg font-semibold text-slate-800">Access Restricted</p>
                <p className="text-sm text-slate-500 mt-1">Only Utility Managers can manage DMA Managers</p>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>
    )
  }

  // Filter DMA managers to show only those belonging to this utility
  const accessibleDMAManagers = isUtilityManager
    ? managers.filter((m) => {
        if (m.utilityId === myUtilityId) return true
        const dma = dmas.find((d) => d.id === m.dmaId)
        return dma?.utilityId === myUtilityId
      })
    : managers

  // Get DMAs that are available for assignment
  const availableDMAs = dmas.filter((d) => {
    if (d.utilityId !== myUtilityId) return false
    if (d.status !== "active") return false
    if (editingManager) {
      return !d.managerId || d.managerId === editingManager.id
    }
    return !d.managerId
  })

  const filteredManagers = accessibleDMAManagers.filter((m) => {
    const searchLower = search.toLowerCase().trim()
    if (!searchLower) return true
    return m.name.toLowerCase().includes(searchLower) ||
           m.email.toLowerCase().includes(searchLower) ||
           (m.dmaName?.toLowerCase() || "").includes(searchLower)
  })

  function openCreateDialog() {
    setEditingManager(null)
    setFormName("")
    setFormEmail("")
    setFormPhone("")
    setFormDmaId("")
    setFormStatus("active")
    setFormPassword("")
    setFormConfirmPassword("")
    setShowPassword(false)
    setDialogOpen(true)
  }

  function openEditDialog(manager: DMAManager) {
    setEditingManager(manager)
    setFormName(manager.name)
    setFormEmail(manager.email)
    setFormPhone(manager.phone ?? "")
    setFormDmaId(manager.dmaId ?? "")
    setFormStatus(manager.status ?? "active")
    setFormPassword("")
    setFormConfirmPassword("")
    setShowPassword(false)
    setDialogOpen(true)
  }

  function openViewDialog(manager: DMAManager) {
    setViewingManager(manager)
    setViewDialogOpen(true)
  }

  async function handleSubmit() {
    if (!formName.trim()) {
      toast.error("Manager name is required")
      return
    }
    if (!formEmail.trim()) {
      toast.error("Email is required")
      return
    }
    if (!myUtilityId) {
      toast.error("Utility ID is required")
      return
    }

    // Password validation
    if (!editingManager) {
      if (!formPassword.trim()) {
        toast.error("Password is required")
        return
      }
      if (formPassword.length < 6) {
        toast.error("Password must be at least 6 characters")
        return
      }
      if (formPassword !== formConfirmPassword) {
        toast.error("Passwords do not match")
        return
      }
    } else {
      if (formPassword && formPassword.length < 6) {
        toast.error("Password must be at least 6 characters")
        return
      }
      if (formPassword && formPassword !== formConfirmPassword) {
        toast.error("Passwords do not match")
        return
      }
    }

    try {
      if (editingManager) {
        const updateData: Record<string, any> = {
          id: editingManager.id,
          name: formName,
          email: formEmail,
          phone: formPhone || null,
          status: formStatus,
          dmaId: formDmaId || null,
        }
        if (formPassword) {
          updateData.password = formPassword
        }
        const response = await fetch("/api/dma-managers", {
          method: "PUT",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(updateData),
        })
        if (!response.ok) {
          const error = await response.json()
          throw new Error(error.error || "Failed to update manager")
        }
        toast.success("Manager updated successfully")
      } else {
        const response = await fetch("/api/dma-managers", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            name: formName,
            email: formEmail,
            phone: formPhone || null,
            password: formPassword,
            status: formStatus,
            utilityId: myUtilityId,
            dmaId: formDmaId || null,
          }),
        })
        if (!response.ok) {
          const error = await response.json()
          throw new Error(error.error || "Failed to create manager")
        }
        toast.success("Manager created successfully")
      }

      setDialogOpen(false)
      await fetchManagers()
      await fetchDMAs()
    } catch (error) {
      console.error("Error saving manager:", error)
      toast.error(error instanceof Error ? error.message : "Operation failed")
    }
  }

  async function handleUnassign(managerId: string) {
    try {
      const manager = managers.find(m => m.id === managerId)
      if (!manager) return

      const response = await fetch("/api/dma-managers", {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          id: managerId,
          name: manager.name,
          email: manager.email,
          phone: manager.phone || null,
          status: manager.status,
          dmaId: null,
        }),
      })

      if (!response.ok) {
        const error = await response.json()
        throw new Error(error.error || "Failed to unassign manager")
      }

      toast.success("Manager unassigned from DMA successfully")
      await fetchManagers()
      await fetchDMAs()
    } catch (error) {
      console.error("Error unassigning manager:", error)
      toast.error(error instanceof Error ? error.message : "Failed to unassign manager")
    }
  }

  async function handleDelete() {
    if (!deleteId) return

    try {
      const response = await fetch(`/api/dma-managers?id=${deleteId}`, {
        method: "DELETE",
      })

      if (!response.ok) {
        const error = await response.json()
        throw new Error(error.error || "Failed to delete manager")
      }

      toast.success("Manager deleted successfully")
      setDeleteId(null)
      await fetchManagers()
      await fetchDMAs()
    } catch (error) {
      console.error("Error deleting manager:", error)
      toast.error(error instanceof Error ? error.message : "Failed to delete manager")
    }
  }

  // Stats
  const totalManagers = accessibleDMAManagers.length
  const activeManagers = accessibleDMAManagers.filter(m => m.status === "active").length
  const assignedManagers = accessibleDMAManagers.filter(m => m.dmaId).length
  const unassignedManagers = accessibleDMAManagers.filter(m => !m.dmaId).length

  // Get initials for avatar
  const getInitials = (name: string) => {
    return name
      .split(" ")
      .map((n) => n[0])
      .join("")
      .toUpperCase()
      .slice(0, 2)
  }

  return (
    <div className="flex flex-col gap-6">
      {/* Modern Header with Stats */}
      <div className="flex flex-col gap-6">
        <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
          <div>
            <h1 className="text-2xl font-bold text-slate-800 flex items-center gap-3">
              <div className="h-10 w-10 rounded-xl bg-gradient-to-br from-violet-500 to-purple-600 flex items-center justify-center shadow-lg shadow-violet-500/20">
                <UserCog className="h-5 w-5 text-white" />
              </div>
              DMA Managers
            </h1>
            <p className="text-slate-500 mt-1">
              {isUtilityManager 
                ? `Manage DMA Managers for ${myUtilityName}`
                : "Manage all DMA Managers in the system"
              }
            </p>
          </div>
          <Button 
            onClick={openCreateDialog}
            className="bg-gradient-to-r from-violet-500 to-purple-600 hover:from-violet-600 hover:to-purple-700 text-white shadow-lg shadow-violet-500/25 hover:shadow-violet-500/40 transition-all duration-300 rounded-xl h-11 px-6"
          >
            <Plus className="h-4 w-4 mr-2" />
            Add Manager
          </Button>
        </div>

        {/* Stats Cards */}
        <div className="grid grid-cols-1 sm:grid-cols-4 gap-4">
          <Card className="border-slate-200/60 shadow-lg shadow-slate-200/20 overflow-hidden group hover:shadow-xl hover:shadow-violet-500/10 transition-all duration-300 bg-gradient-to-br from-violet-50/30 to-white">
            <CardContent className="p-5">
              <div className="flex items-center gap-4">
                <div className="h-12 w-12 rounded-xl bg-gradient-to-br from-violet-500 to-purple-600 flex items-center justify-center shadow-lg shadow-violet-500/20 group-hover:scale-110 transition-transform duration-300">
                  <Users className="h-6 w-6 text-white" />
                </div>
                <div>
                  <p className="text-sm font-medium text-slate-500">Total Managers</p>
                  <p className="text-2xl font-bold text-slate-800">{totalManagers}</p>
                </div>
              </div>
            </CardContent>
          </Card>

          <Card className="border-slate-200/60 shadow-lg shadow-slate-200/20 overflow-hidden group hover:shadow-xl hover:shadow-green-500/10 transition-all duration-300 bg-gradient-to-br from-green-50/30 to-white">
            <CardContent className="p-5">
              <div className="flex items-center gap-4">
                <div className="h-12 w-12 rounded-xl bg-gradient-to-br from-green-500 to-emerald-600 flex items-center justify-center shadow-lg shadow-green-500/20 group-hover:scale-110 transition-transform duration-300">
                  <CheckCircle2 className="h-6 w-6 text-white" />
                </div>
                <div>
                  <p className="text-sm font-medium text-slate-500">Active</p>
                  <p className="text-2xl font-bold text-slate-800">{activeManagers}</p>
                </div>
              </div>
            </CardContent>
          </Card>

          <Card className="border-slate-200/60 shadow-lg shadow-slate-200/20 overflow-hidden group hover:shadow-xl hover:shadow-blue-500/10 transition-all duration-300 bg-gradient-to-br from-blue-50/30 to-white">
            <CardContent className="p-5">
              <div className="flex items-center gap-4">
                <div className="h-12 w-12 rounded-xl bg-gradient-to-br from-blue-500 to-indigo-600 flex items-center justify-center shadow-lg shadow-blue-500/20 group-hover:scale-110 transition-transform duration-300">
                  <MapPin className="h-6 w-6 text-white" />
                </div>
                <div>
                  <p className="text-sm font-medium text-slate-500">Assigned</p>
                  <p className="text-2xl font-bold text-slate-800">{assignedManagers}</p>
                </div>
              </div>
            </CardContent>
          </Card>

          <Card className="border-slate-200/60 shadow-lg shadow-slate-200/20 overflow-hidden group hover:shadow-xl hover:shadow-amber-500/10 transition-all duration-300 bg-gradient-to-br from-amber-50/30 to-white">
            <CardContent className="p-5">
              <div className="flex items-center gap-4">
                <div className="h-12 w-12 rounded-xl bg-gradient-to-br from-amber-500 to-orange-600 flex items-center justify-center shadow-lg shadow-amber-500/20 group-hover:scale-110 transition-transform duration-300">
                  <Building2 className="h-6 w-6 text-white" />
                </div>
                <div>
                  <p className="text-sm font-medium text-slate-500">Unassigned</p>
                  <p className="text-2xl font-bold text-slate-800">{unassignedManagers}</p>
                </div>
              </div>
            </CardContent>
          </Card>
        </div>
      </div>

      {/* Modern Search */}
      <div className="flex flex-col sm:flex-row gap-4 items-start sm:items-center justify-between">
        <div className="relative w-full sm:w-80">
          <div className="absolute inset-0 rounded-xl bg-gradient-to-r from-violet-400/10 to-purple-500/10 blur-lg opacity-0 focus-within:opacity-100 transition-opacity duration-300 pointer-events-none" />
          <Search className="absolute left-4 top-1/2 h-4 w-4 -translate-y-1/2 text-slate-400 pointer-events-none" />
          <Input
            placeholder="Search by name, email, or DMA..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="pl-11 h-11 bg-slate-50/80 border-slate-200/80 rounded-xl focus:border-violet-400 focus:ring-violet-400/20 shadow-sm"
          />
        </div>
        <div className="flex items-center gap-2 text-sm text-slate-500">
          <UserCog className="h-4 w-4" />
          <span>{filteredManagers.length} manager{filteredManagers.length !== 1 ? 's' : ''}</span>
        </div>
      </div>

      {/* Modern Table */}
      <Card className="border-slate-200/60 shadow-lg shadow-slate-200/20 overflow-hidden">
        <CardContent className="p-0">
          <div className="overflow-x-auto">
            <Table>
              <TableHeader>
                <TableRow className="bg-gradient-to-r from-slate-50 to-slate-100/80 hover:from-slate-50 hover:to-slate-100/80 border-b border-slate-200/60">
                  <TableHead className="font-semibold text-slate-600 py-4 px-6">
                    <div className="flex items-center gap-2">
                      <User className="h-4 w-4" />
                      Manager
                    </div>
                  </TableHead>
                  <TableHead className="font-semibold text-slate-600 py-4 px-6">
                    <div className="flex items-center gap-2">
                      <Mail className="h-4 w-4" />
                      Contact
                    </div>
                  </TableHead>
                  <TableHead className="font-semibold text-slate-600 py-4 px-6">
                    <div className="flex items-center gap-2">
                      <MapPin className="h-4 w-4" />
                      Assigned DMA
                    </div>
                  </TableHead>
                  <TableHead className="font-semibold text-slate-600 py-4 px-6">
                    <div className="flex items-center gap-2">
                      <CheckCircle2 className="h-4 w-4" />
                      Status
                    </div>
                  </TableHead>
                  <TableHead className="font-semibold text-slate-600 py-4 px-6 text-right">Actions</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {filteredManagers.length === 0 ? (
                  <TableRow>
                    <TableCell colSpan={5} className="py-16 text-center">
                      <div className="flex flex-col items-center gap-4">
                        <div className="h-16 w-16 rounded-2xl bg-gradient-to-br from-slate-100 to-slate-200 flex items-center justify-center">
                          <UserCog className="h-8 w-8 text-slate-400" />
                        </div>
                        <div>
                          <p className="text-lg font-semibold text-slate-800">No DMA managers found</p>
                          <p className="text-sm text-slate-500 mt-1">
                            {search ? "Try adjusting your search terms" : "Get started by creating your first DMA manager"}
                          </p>
                        </div>
                        {!search && (
                          <Button 
                            onClick={openCreateDialog}
                            className="mt-2 bg-gradient-to-r from-violet-500 to-purple-600 hover:from-violet-600 hover:to-purple-700 text-white shadow-lg shadow-violet-500/25 rounded-xl"
                          >
                            <Plus className="h-4 w-4 mr-2" />
                            Add DMA Manager
                          </Button>
                        )}
                      </div>
                    </TableCell>
                  </TableRow>
                ) : (
                  filteredManagers.map((manager) => {
                    const dma = dmas.find((d) => d.id === manager.dmaId)
                    const isInactive = manager.status === "inactive"
                    
                    return (
                      <TableRow 
                        key={manager.id} 
                        className={cn(
                          "border-b border-slate-100 transition-all duration-200",
                          isInactive 
                            ? "bg-red-50/30 hover:bg-red-50/50" 
                            : "hover:bg-violet-50/50"
                        )}
                      >
                        {/* Manager Info with Avatar */}
                        <TableCell className="py-4 px-6">
                          <div className="flex items-center gap-3">
                            <Avatar className={cn(
                              "h-10 w-10 shadow-lg transition-all duration-300",
                              isInactive 
                                ? "ring-2 ring-red-200" 
                                : "ring-2 ring-violet-200"
                            )}>
                              <AvatarFallback className={cn(
                                "text-sm font-semibold",
                                isInactive
                                  ? "bg-gradient-to-br from-red-400 to-rose-500 text-white"
                                  : "bg-gradient-to-br from-violet-500 to-purple-600 text-white"
                              )}>
                                {getInitials(manager.name)}
                              </AvatarFallback>
                            </Avatar>
                            <div>
                              <p className="font-semibold text-slate-800">{manager.name}</p>
                              <p className="text-xs text-slate-500">DMA Manager</p>
                            </div>
                          </div>
                        </TableCell>

                        {/* Contact Info */}
                        <TableCell className="py-4 px-6">
                          <div className="flex flex-col gap-1">
                            <div className="flex items-center gap-2 text-sm text-slate-600">
                              <Mail className="h-3.5 w-3.5 text-slate-400" />
                              <span className="truncate max-w-[200px]">{manager.email}</span>
                            </div>
                            {manager.phone && (
                              <div className="flex items-center gap-2 text-sm text-slate-500">
                                <Phone className="h-3.5 w-3.5 text-slate-400" />
                                <span>{manager.phone}</span>
                              </div>
                            )}
                          </div>
                        </TableCell>

                        {/* Assigned DMA */}
                        <TableCell className="py-4 px-6">
                          {dma ? (
                            <div className="flex items-center gap-2">
                              <div className="h-8 w-8 rounded-lg bg-gradient-to-br from-cyan-100 to-blue-100 flex items-center justify-center">
                                <MapPin className="h-4 w-4 text-cyan-600" />
                              </div>
                              <span className="font-medium text-slate-700">{dma.name}</span>
                            </div>
                          ) : (
                            <Badge variant="outline" className="text-orange-600 border-orange-200 bg-orange-50 hover:bg-orange-100">
                              <MapPin className="h-3 w-3 mr-1" />
                              Unassigned
                            </Badge>
                          )}
                        </TableCell>

                        {/* Status */}
                        <TableCell className="py-4 px-6">
                          <EntityStatusBadge status={(manager.status as EntityStatus) ?? "active"} />
                        </TableCell>

                        {/* Actions */}
                        <TableCell className="py-4 px-6 text-right">
                          <DropdownMenu>
                            <DropdownMenuTrigger asChild>
                              <Button 
                                variant="ghost" 
                                size="icon" 
                                className="h-9 w-9 rounded-lg hover:bg-slate-100 transition-colors"
                              >
                                <MoreHorizontal className="h-4 w-4 text-slate-500" />
                                <span className="sr-only">Actions</span>
                              </Button>
                            </DropdownMenuTrigger>
                            <DropdownMenuContent 
                              align="end" 
                              className="w-48 rounded-xl shadow-lg shadow-slate-200/50 border-slate-200/60"
                            >
                              <DropdownMenuItem 
                                onClick={() => openViewDialog(manager)} 
                                className="rounded-lg gap-2 cursor-pointer"
                              >
                                <Eye className="h-4 w-4 text-blue-500" />
                                View Details
                              </DropdownMenuItem>
                              <DropdownMenuItem 
                                onClick={() => openEditDialog(manager)} 
                                className="rounded-lg gap-2 cursor-pointer"
                              >
                                <Pencil className="h-4 w-4 text-violet-500" />
                                Edit Manager
                              </DropdownMenuItem>
                              {manager.dmaId && (
                                <DropdownMenuItem
                                  onClick={() => handleUnassign(manager.id)}
                                  className="text-orange-600 focus:text-orange-600 focus:bg-orange-50 rounded-lg gap-2 cursor-pointer"
                                >
                                  <MapPin className="h-4 w-4" />
                                  Unassign from DMA
                                </DropdownMenuItem>
                              )}
                              <DropdownMenuItem
                                onClick={() => setDeleteId(manager.id)}
                                className="text-red-600 focus:text-red-600 focus:bg-red-50 rounded-lg gap-2 cursor-pointer"
                              >
                                <Trash2 className="h-4 w-4" />
                                Delete Manager
                              </DropdownMenuItem>
                            </DropdownMenuContent>
                          </DropdownMenu>
                        </TableCell>
                      </TableRow>
                    )
                  })
                )}
              </TableBody>
            </Table>
          </div>
        </CardContent>
      </Card>

      {/* Modern Create/Edit Dialog */}
      <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
        <DialogContent className="sm:max-w-lg max-h-[85vh] flex flex-col bg-white/95 backdrop-blur-xl border-slate-200/50 shadow-2xl shadow-slate-200/50 rounded-2xl">
          <DialogHeader className="flex-shrink-0">
            <DialogTitle className="flex items-center gap-2 text-xl">
              <div className="h-8 w-8 rounded-lg bg-gradient-to-br from-violet-500 to-purple-600 flex items-center justify-center">
                {editingManager ? (
                  <Pencil className="h-4 w-4 text-white" />
                ) : (
                  <Plus className="h-4 w-4 text-white" />
                )}
              </div>
              {editingManager ? "Edit DMA Manager" : "Add DMA Manager"}
            </DialogTitle>
            <DialogDescription>
              {editingManager 
                ? "Update the DMA Manager details below."
                : `Create a new DMA Manager for ${myUtilityName}. They will be assigned to the selected DMA.`
              }
            </DialogDescription>
          </DialogHeader>
          <div className="flex flex-col gap-5 py-4 overflow-y-auto flex-1 min-h-0">
            <div className="flex flex-col gap-2">
              <Label htmlFor="manager-name" className="text-sm font-medium text-slate-700">Full Name</Label>
              <Input
                id="manager-name"
                value={formName}
                onChange={(e) => setFormName(e.target.value)}
                placeholder="e.g., Jane Doe"
                className="h-11 bg-slate-50/80 border-slate-200/80 rounded-xl focus:border-violet-400 focus:ring-violet-400/20"
              />
            </div>
            <div className="flex flex-col gap-2">
              <Label htmlFor="manager-email" className="text-sm font-medium text-slate-700">Email</Label>
              <Input
                id="manager-email"
                type="email"
                value={formEmail}
                onChange={(e) => setFormEmail(e.target.value)}
                placeholder="e.g., jane@example.com"
                className="h-11 bg-slate-50/80 border-slate-200/80 rounded-xl focus:border-violet-400 focus:ring-violet-400/20"
              />
            </div>
            <div className="flex flex-col gap-2">
              <Label htmlFor="manager-phone" className="text-sm font-medium text-slate-700">Phone</Label>
              <Input
                id="manager-phone"
                type="tel"
                value={formPhone}
                onChange={(e) => setFormPhone(e.target.value)}
                placeholder="e.g., +255 22 211 1001"
                className="h-11 bg-slate-50/80 border-slate-200/80 rounded-xl focus:border-violet-400 focus:ring-violet-400/20"
              />
            </div>
            
            {/* Utility Info */}
            <div className="rounded-xl border border-violet-200/80 bg-gradient-to-r from-violet-50/50 to-purple-50/50 p-4">
              <div className="flex items-center gap-2 text-sm">
                <Building2 className="h-4 w-4 text-violet-600" />
                <span className="font-semibold text-violet-700">{myUtilityName}</span>
                <span className="text-violet-400">•</span>
                <span className="text-violet-600 text-xs">Your utility</span>
              </div>
              <p className="text-xs text-violet-500/80 mt-2">
                The DMA Manager will belong to this utility
              </p>
            </div>

            <div className="flex flex-col gap-2">
              <Label className="text-sm font-medium text-slate-700">Assign to DMA</Label>
              <Select value={formDmaId} onValueChange={setFormDmaId}>
                <SelectTrigger className="h-11 bg-slate-50/80 border-slate-200/80 rounded-xl">
                  <SelectValue placeholder="Select a DMA" />
                </SelectTrigger>
                <SelectContent className="rounded-xl shadow-lg shadow-slate-200/50">
                  {availableDMAs.length === 0 ? (
                    <div className="px-2 py-4 text-center text-sm text-muted-foreground">
                      No unassigned DMAs available
                    </div>
                  ) : (
                    availableDMAs.map((d) => (
                      <SelectItem key={d.id} value={d.id} className="rounded-lg">
                        <div className="flex items-center gap-2">
                          <MapPin className="h-4 w-4 text-blue-500" />
                          {d.name}
                        </div>
                      </SelectItem>
                    ))
                  )}
                </SelectContent>
              </Select>
              {availableDMAs.length === 0 && !editingManager && (
                <p className="text-xs text-amber-600">
                  All DMAs in your utility have been assigned. Create a new DMA first or reassign existing managers.
                </p>
              )}
            </div>
            
            <div className="flex flex-col gap-2">
              <Label className="text-sm font-medium text-slate-700">Status</Label>
              <Select value={formStatus} onValueChange={setFormStatus}>
                <SelectTrigger className="h-11 bg-slate-50/80 border-slate-200/80 rounded-xl">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent className="rounded-xl shadow-lg shadow-slate-200/50">
                  <SelectItem value="active" className="rounded-lg">
                    <div className="flex items-center gap-2">
                      <CheckCircle2 className="h-4 w-4 text-emerald-500" />
                      Active
                    </div>
                  </SelectItem>
                  <SelectItem value="inactive" className="rounded-lg">
                    <div className="flex items-center gap-2">
                      <div className="h-4 w-4 rounded-full bg-slate-400" />
                      Inactive
                    </div>
                  </SelectItem>
                </SelectContent>
              </Select>
            </div>
            
            {/* Password Section */}
            <div className="border-t border-slate-200 pt-4">
              <Label className="flex items-center gap-2 mb-3 text-sm font-medium text-slate-700">
                <Lock className="h-4 w-4" />
                {editingManager ? "Change Password (leave blank to keep current)" : "Account Password"}
              </Label>
              <div className="flex flex-col gap-3">
                <div className="relative">
                  <Input
                    type={showPassword ? "text" : "password"}
                    value={formPassword}
                    onChange={(e) => setFormPassword(e.target.value)}
                    placeholder={editingManager ? "Enter new password (optional)" : "Enter password (min 6 characters)"}
                    className="h-11 bg-slate-50/80 border-slate-200/80 rounded-xl focus:border-violet-400 focus:ring-violet-400/20 pr-10"
                  />
                  <Button
                    type="button"
                    variant="ghost"
                    size="icon"
                    className="absolute right-0 top-0 h-full px-3 hover:bg-transparent"
                    onClick={() => setShowPassword(!showPassword)}
                  >
                    {showPassword ? (
                      <EyeOff className="h-4 w-4 text-muted-foreground" />
                    ) : (
                      <Eye className="h-4 w-4 text-muted-foreground" />
                    )}
                  </Button>
                </div>
                <Input
                  type={showPassword ? "text" : "password"}
                  value={formConfirmPassword}
                  onChange={(e) => setFormConfirmPassword(e.target.value)}
                  placeholder="Confirm password"
                  className="h-11 bg-slate-50/80 border-slate-200/80 rounded-xl focus:border-violet-400 focus:ring-violet-400/20"
                />
              </div>
            </div>
          </div>
          <DialogFooter className="gap-2 sm:gap-0">
            <Button variant="outline" onClick={() => setDialogOpen(false)} className="rounded-xl">
              Cancel
            </Button>
            <Button 
              onClick={handleSubmit}
              className="bg-gradient-to-r from-violet-500 to-purple-600 hover:from-violet-600 hover:to-purple-700 text-white shadow-lg shadow-violet-500/25 rounded-xl"
            >
              {editingManager ? (
                <>
                  <Sparkles className="h-4 w-4 mr-2" />
                  Save Changes
                </>
              ) : (
                <>
                  <Plus className="h-4 w-4 mr-2" />
                  Create Manager
                </>
              )}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Delete Confirmation */}
      <ConfirmDialog
        open={!!deleteId}
        onOpenChange={() => setDeleteId(null)}
        title="Delete DMA Manager"
        description="Are you sure you want to delete this DMA Manager? This will unassign them from their DMA. This action cannot be undone."
        confirmLabel="Delete Manager"
        onConfirm={handleDelete}
      />

      {/* View Details Dialog */}
      <Dialog open={viewDialogOpen} onOpenChange={setViewDialogOpen}>
        <DialogContent className="sm:max-w-lg bg-white/95 backdrop-blur-xl border-slate-200/50 shadow-2xl shadow-slate-200/50 rounded-2xl">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2 text-xl">
              <div className="h-8 w-8 rounded-lg bg-gradient-to-br from-blue-500 to-indigo-600 flex items-center justify-center">
                <Eye className="h-4 w-4 text-white" />
              </div>
              DMA Manager Details
            </DialogTitle>
          </DialogHeader>
          {viewingManager && (
            <div className="flex flex-col gap-6 py-4">
              {/* Profile Header */}
              <div className="flex items-center gap-4 p-4 rounded-xl bg-gradient-to-r from-violet-50/50 to-purple-50/50 border border-violet-200/50">
                <Avatar className="h-16 w-16 shadow-lg ring-2 ring-violet-200">
                  <AvatarFallback className="text-lg font-semibold bg-gradient-to-br from-violet-500 to-purple-600 text-white">
                    {getInitials(viewingManager.name)}
                  </AvatarFallback>
                </Avatar>
                <div>
                  <h3 className="text-lg font-semibold text-slate-800">{viewingManager.name}</h3>
                  <p className="text-sm text-slate-500">DMA Manager</p>
                  <EntityStatusBadge status={viewingManager.status} />
                </div>
              </div>

              {/* Details Grid */}
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div className="flex items-center gap-3 p-3 rounded-xl bg-slate-50/80 border border-slate-200/60">
                  <div className="h-10 w-10 rounded-lg bg-blue-100 flex items-center justify-center">
                    <Mail className="h-5 w-5 text-blue-600" />
                  </div>
                  <div>
                    <p className="text-xs text-slate-500">Email</p>
                    <p className="text-sm font-medium text-slate-700">{viewingManager.email}</p>
                  </div>
                </div>

                <div className="flex items-center gap-3 p-3 rounded-xl bg-slate-50/80 border border-slate-200/60">
                  <div className="h-10 w-10 rounded-lg bg-green-100 flex items-center justify-center">
                    <Phone className="h-5 w-5 text-green-600" />
                  </div>
                  <div>
                    <p className="text-xs text-slate-500">Phone</p>
                    <p className="text-sm font-medium text-slate-700">{viewingManager.phone || 'Not provided'}</p>
                  </div>
                </div>

                <div className="flex items-center gap-3 p-3 rounded-xl bg-slate-50/80 border border-slate-200/60">
                  <div className="h-10 w-10 rounded-lg bg-violet-100 flex items-center justify-center">
                    <Building2 className="h-5 w-5 text-violet-600" />
                  </div>
                  <div>
                    <p className="text-xs text-slate-500">Utility</p>
                    <p className="text-sm font-medium text-slate-700">{viewingManager.utilityName || myUtilityName}</p>
                  </div>
                </div>

                <div className="flex items-center gap-3 p-3 rounded-xl bg-slate-50/80 border border-slate-200/60">
                  <div className="h-10 w-10 rounded-lg bg-cyan-100 flex items-center justify-center">
                    <MapPin className="h-5 w-5 text-cyan-600" />
                  </div>
                  <div>
                    <p className="text-xs text-slate-500">Assigned DMA</p>
                    {viewingManager.dmaId ? (
                      <p className="text-sm font-medium text-slate-700">{dmas.find(d => d.id === viewingManager.dmaId)?.name || viewingManager.dmaName}</p>
                    ) : (
                      <Badge variant="outline" className="text-orange-600 border-orange-200 bg-orange-50">
                        Unassigned
                      </Badge>
                    )}
                  </div>
                </div>
              </div>
            </div>
          )}
          <DialogFooter>
            <Button variant="outline" onClick={() => setViewDialogOpen(false)} className="rounded-xl">
              Close
            </Button>
            <Button 
              onClick={() => {
                setViewDialogOpen(false)
                if (viewingManager) openEditDialog(viewingManager)
              }}
              className="bg-gradient-to-r from-violet-500 to-purple-600 hover:from-violet-600 hover:to-purple-700 text-white shadow-lg shadow-violet-500/25 rounded-xl"
            >
              <Pencil className="h-4 w-4 mr-2" />
              Edit Manager
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  )
}
